mapper.select:
SELECT  n.*, u.username AS username, nc.category_name AS categoryName,
(SELECT COUNT(*) FROM tb_comments WHERE news_id = n.news_id) AS commentCount,
(SELECT COUNT(*) FROM tb_history WHERE news_id = n.news_id) AS viewCount,
(SELECT COUNT(*) FROM tb_likes WHERE news_id = n.news_id) AS likeCount,
(SELECT COUNT(*) FROM tb_favorites WHERE news_id = n.news_id) AS collectCount
FROM tb_news n
LEFT JOIN tb_users u ON n.user_id = u.user_id
LEFT JOIN tb_news_categories nc ON n.category_id = nc.category_id

     AND n.title LIKE CONCAT('%', #{title}, '%')
    AND n.content = #{content}
    AND n.category_id = #{categoryId}
    AND n.user_id = #{userId}
    AND n.status = #{status}
    AND n.news_id = #{newsId}

ORDER BY n.news_id DESC

mapper.update:
update tb_news
title = #{title}, content = #{content}, img = #{img}, category_id = #{categoryId}, user_id = #{userId}, status = #{status}, remark = #{remark}, create_time = #{createTime}, update_time = #{updateTime}, create_by = #{createBy}, update_by = #{updateBy},
where news_id = #{newsId}
